// Per ogni clip del bank: 3 job draft (instagram, facebook, tiktok).
// IG/FB: file con logo (contenuto brand legittimo) + media_public_url
//        servito da media.adoff.app (Meta scarica da URL pubblico).
// TikTok: variante SENZA logo (ToS) via /opt/n8n/local-files/adoff-bank
//        (symlink al bank) + no_logo_variant=true (FILE_UPLOAD, no URL).
const BANK = '/home/mrxxx/adoff/sviluppo/marketing/video-engine/output';
const TT_DIR = '/opt/n8n/local-files/adoff-bank';
const MEDIA_BASE = 'https://media.adoff.app';
let man;
try { man = JSON.parse($input.first().json.stdout || '[]'); } catch (e) { man = []; }
// batch-render scrive {generated,count,items:[...]}; tollera anche array puro.
if (man && !Array.isArray(man) && Array.isArray(man.items)) man = man.items;
if (!Array.isArray(man)) man = [];
const out = [];
for (const m of man) {
  if (!m || !m.file) continue;
  const fname = String(m.file).split('/').pop();          // A1-x__it.mp4
  const fbase = fname.replace(/\.mp4$/, '');               // A1-x__it
  const std = `${BANK}/${m.file}`;                         // host (con logo)
  const pub = `${MEDIA_BASE}/${fname}`;                    // URL pubblico IG/FB
  const ttPath = `${TT_DIR}/${fbase}__nologo.mp4`;         // TikTok no-logo
  const hashtags = Array.isArray(m.hashtagSet) ? m.hashtagSet.join(' ') : (m.hashtagSet || '');
  const lang = m.lang || 'it';
  const common = { brand: 'adoff', media_type: 'video', caption: '', hashtags, lang, ai_generated: true, src_id: m.id };
  out.push({ json: { ...common, platform: 'instagram', account_ref: 'adoff', media_path: std,    media_public_url: pub, no_logo_variant: false } });
  out.push({ json: { ...common, platform: 'facebook',  account_ref: 'adoff', media_path: std,    media_public_url: pub, no_logo_variant: false } });
  out.push({ json: { ...common, platform: 'tiktok',    account_ref: 'adoff', media_path: ttPath, media_public_url: '',  no_logo_variant: true  } });
}
return out;

// INSERT idempotente: salta se esiste gia' un job (stato vivo) per
// stessa platform+media_path. La thin admin UI poi approva i draft.
function lit(s){return String(s == null ? '' : s).replace(/'/g,"''");}
const out=[];
for (const it of $input.all()){
  const j=it.json;
  const sql=
    `INSERT INTO adoff_autopilot.social_posts `+
    `(brand,platform,account_ref,media_type,media_path,media_public_url,`+
    `no_logo_variant,caption,hashtags,lang,ai_generated,status) `+
    `SELECT '${lit(j.brand)}','${lit(j.platform)}','${lit(j.account_ref)}',`+
    `'${lit(j.media_type)}','${lit(j.media_path)}',`+
    `${j.media_public_url?`'${lit(j.media_public_url)}'`:'NULL'},`+
    `${j.no_logo_variant?'true':'false'},`+
    `'${lit(j.caption)}','${lit(j.hashtags)}','${lit(j.lang)}',`+
    `${j.ai_generated?'true':'false'},'draft' `+
    `WHERE NOT EXISTS (SELECT 1 FROM adoff_autopilot.social_posts `+
    `WHERE platform='${lit(j.platform)}' AND media_path='${lit(j.media_path)}' `+
    `AND status IN ('draft','approved','publishing','published'));`;
  out.push({json:{platform:j.platform,src_id:j.src_id,sql}});
}
return out;

const items=$input.all().map(i=>i.json);
const n=items.length;
const byPlat={};
for(const i of items){byPlat[i.platform]=(byPlat[i.platform]||0)+1;}
const summary=Object.entries(byPlat).map(([p,c])=>`• ${p}: ${c}`).join('\n');
const text=`📤 *AdOff Social Enqueue* — ${n} job draft accodati\n\n${summary}\n\nRevisiona e approva nella Admin UI (gate consenso umano).`;
return [{json:{text}}];
